import sys

class ListNode:
    __slots__ = ('val', 'next', 'prev')
    def __init__(self, val: int):
        self.val = val
        self.next = None
        self.prev = None

class Solution:
    def reverseList(self, head: ListNode) -> ListNode:
        cur = head
        new_head = None
        while cur:
            # swap next and prev
            cur.next, cur.prev = cur.prev, cur.next
            new_head = cur  # last visited becomes new head
            cur = cur.prev  # move to original next (now prev)
        return new_head

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    try:
        n = int(next(it))
    except StopIteration:
        sys.exit(0)
    vals = []
    for _ in range(n):
        try:
            vals.append(int(next(it)))
        except StopIteration:
            break
    # build doubly linked list
    head = None
    prev = None
    for v in vals:
        node = ListNode(v)
        if not head:
            head = node
        if prev:
            prev.next = node
            node.prev = prev
        prev = node
    sol = Solution()
    new_head = sol.reverseList(head)
    # output
    out = []
    cur = new_head
    while cur:
        out.append(str(cur.val))
        cur = cur.next
    print(' '.join(out))

