#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode* next;
    ListNode* prev;
    ListNode(int x) : val(x), next(nullptr), prev(nullptr) {}
};

class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        ListNode* cur = head;
        ListNode* new_head = nullptr;
        while (cur) {
            // swap next and prev
            ListNode* nxt = cur->next;
            cur->next = cur->prev;
            cur->prev = nxt;
            new_head = cur;
            cur = cur->prev; // move to original next
        }
        return new_head;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals;
    vals.reserve(n);
    for (int i = 0; i < n; ++i) {
        int x;
        if (!(cin >> x)) break;
        vals.push_back(x);
    }
    ListNode* head = nullptr;
    ListNode* prev = nullptr;
    for (int v : vals) {
        ListNode* node = new ListNode(v);
        if (!head) head = node;
        if (prev) {
            prev->next = node;
            node->prev = prev;
        }
        prev = node;
    }
    Solution sol;
    ListNode* new_head = sol.reverseList(head);
    vector<int> out;
    for (ListNode* cur = new_head; cur; cur = cur->next) {
        out.push_back(cur->val);
    }
    for (size_t i = 0; i < out.size(); ++i) {
        if (i) cout << ' ';
        cout << out[i];
    }
    cout << "\n";
    return 0;
}
